class Solution:
    def findKthLargest(self, nums, k):
        import heapq
        heap = nums[:k]
        heapq.heapify(heap)
        for num in nums[k:]:
            if num > heap[0]:
                heapq.heappushpop(heap, num)
        return heap[0]

